    {
      "path": "routes/general-browser-agent-routes.js",
      "register": "registerGeneralBrowserAgentRoutes",
      "enabled": true,
      "note": "General browser agent + founder-authorized signup (POST /api/v1/browser-agent/run|signup|signup/sync|signup/approve). founder_authority:true completes paid checkout from FOUNDER_PAYMENT_* Railway vault; without it, stops at consent."
