    },
    {
      "path": "routes/lifeos-ui-directives-routes.js",
      "register": "registerLifeosUiDirectivesRoutes",
      "enabled": true
    },
    {
      "path": "routes/lifeos-biological-age-routes.js",
      "register": "registerBiologicalAgeRoutes",
      "enabled": true,
      "note": "LifeOS biological age REST surface. Auto-register entry added so the governed factory can ship the route and module-health can prove it LIVE."
    },
    {
      "path": "routes/lifeos-twin-simulator-routes.js",
